import java.util.*;

public class Solution {

    private static boolean isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }

    public static String solve(String s) {
        // 1. Preprocessing: Count frequencies, track first index, and list vowel positions
        Map<Character, Integer> freq = new HashMap<>();
        Map<Character, Integer> firstIndex = new HashMap<>();
        List<Integer> vowelIndices = new ArrayList<>();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (isVowel(c)) {
                vowelIndices.add(i);

                // Update frequency
                freq.put(c, freq.getOrDefault(c, 0) + 1);

                // Track first index
                if (!firstIndex.containsKey(c)) {
                    firstIndex.put(c, i);
                }
            }
        }

        // 2. Determine the Sorted Order of Unique Vowels
        List<Character> uniqueVowels = new ArrayList<>(freq.keySet());

        // Sort criteria:
        // 1. Frequency (Descending)
        // 2. First appearance index (Ascending)
        Collections.sort(uniqueVowels, new Comparator<Character>() {
            @Override
            public int compare(Character v1, Character v2) {
                int freq1 = freq.get(v1);
                int freq2 = freq.get(v2);

                // Compare frequencies (Descending: v2 vs v1)
                if (freq1 != freq2) {
                    return Integer.compare(freq2, freq1);
                } else {
                    // Frequencies are equal, compare first index (Ascending: v1 vs v2)
                    int index1 = firstIndex.get(v1);
                    int index2 = firstIndex.get(v2);
                    return Integer.compare(index1, index2);
                }
            }
        });

        // 3. Generate the Replacement Sequence
        StringBuilder replacementSequence = new StringBuilder();
        for (char v : uniqueVowels) {
            int count = freq.get(v);
            for (int i = 0; i < count; i++) {
                replacementSequence.append(v);
            }
        }
        String sortedVowels = replacementSequence.toString();

        // 4. Reconstruct the String
        char[] resultChars = s.toCharArray();

        // Replace the vowel characters at their original positions
        for (int i = 0; i < vowelIndices.size(); i++) {
            int originalIndex = vowelIndices.get(i);
            char replacementChar = sortedVowels.charAt(i);
            resultChars[originalIndex] = replacementChar;
        }

        return new String(resultChars);
    }
}

