            char c = s.charAt(i);
            if (VOWELS.contains(c)) {
                vowelIndices.add(i);
                allVowels.add(c);

                counts.put(c, counts.getOrDefault(c, 0) + 1);
                if (!firstIndexMap.containsKey(c)) {
                    firstIndexMap.put(c, i);
                }
            }
        }

        if (allVowels.isEmpty()) {
            return s;
        }

        // 2. Collect Vowel Info objects
        List<VowelInfo> uniqueVowelInfos = new ArrayList<>();
